package dev.harrison.rendacomcarro.dashboard.application;
import dev.harrison.rendacomcarro.expense.infrastructure.ExpenseRepository;import dev.harrison.rendacomcarro.finance.infrastructure.FinancialObligationRepository;import dev.harrison.rendacomcarro.goal.application.GoalService;import dev.harrison.rendacomcarro.operation.application.*;import dev.harrison.rendacomcarro.operation.domain.*;import dev.harrison.rendacomcarro.operation.infrastructure.OperationalDayRepository;import java.math.*;import java.time.*;import java.util.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;
@Service public class DashboardService {private final OperationalDayRepository days;private final ShiftService shifts;private final RevenueService revenues;private final ExpenseRepository expenses;private final FinancialObligationRepository obligations;private final GoalService goals;public DashboardService(OperationalDayRepository d,ShiftService s,RevenueService r,ExpenseRepository e,FinancialObligationRepository o,GoalService g){days=d;shifts=s;revenues=r;expenses=e;obligations=o;goals=g;}
 @Transactional(readOnly=true)public DashboardSnapshot snapshot(LocalDate date){var day=days.findAllByOrderByDateDesc().stream().filter(d->d.getDate().equals(date)&&d.getStatus()!=OperationalDayStatus.CANCELLED).findFirst();List<Shift> dayShifts=day.map(d->shifts.listByDay(d.getId())).orElse(List.of());BigDecimal revenue=revenues.sumByCompetence(date);BigDecimal expense=expenses.findAllByCompetenceDate(date).stream().filter(e->e.getStatus().equals("ACTIVE")&&!e.getClassification().name().equals("PERSONAL")).map(e->e.getAmount()).reduce(BigDecimal.ZERO,BigDecimal::add);BigDecimal margin=revenue.subtract(expense).setScale(2);Duration duration=dayShifts.stream().map(Shift::getDuration).reduce(Duration.ZERO,Duration::plus);BigDecimal distance=dayShifts.stream().map(Shift::getDistance).reduce(BigDecimal.ZERO,BigDecimal::add).setScale(1);BigDecimal hours=new BigDecimal(duration.toMinutes()).divide(new BigDecimal("60"),4,RoundingMode.HALF_UP);BigDecimal perHour=hours.signum()==0?BigDecimal.ZERO.setScale(2):revenue.divide(hours,2,RoundingMode.HALF_UP);BigDecimal perKm=distance.signum()==0?BigDecimal.ZERO.setScale(2):revenue.divide(distance,2,RoundingMode.HALF_UP);Optional<DashboardSnapshot.CurrentShiftView> current=dayShifts.stream().filter(s->s.getStatus()==ShiftStatus.OPEN).findFirst().map(s->new DashboardSnapshot.CurrentShiftView(s.getId(),s.getStartedAt(),s.getDuration(),BigDecimal.ZERO,s.getDistance(),BigDecimal.ZERO));BigDecimal debt=obligations.findAll().stream().filter(o->o.getStatus().name().equals("ACTIVE")).map(o->o.getCurrentBalance()).reduce(BigDecimal.ZERO,BigDecimal::add).setScale(2);var goal=goals.find(YearMonth.from(date));BigDecimal target=goal.map(g->g.getPersonalNetGoal()).orElse(BigDecimal.ZERO.setScale(2));Set<LocalDate> planned=goal.map(g->goals.plannedDays(g.getId()).stream().map(x->x.getWorkDate()).collect(java.util.stream.Collectors.toSet())).orElse(Set.of());BigDecimal required=goals.project(YearMonth.from(date),target,revenue,planned).requiredPerDay();var recent=expenses.findAllByOrderByExpenseDateDesc().stream().limit(5).map(e->new DashboardSnapshot.RecentExpenseView(e.getExpenseDate(),e.getCategory().getName(),e.getAmount())).toList();return new DashboardSnapshot(date,current,day.isPresent()&&day.get().getStatus()==OperationalDayStatus.IN_PROGRESS,revenue,margin,margin,revenue.subtract(expense),target,required,duration,distance,perHour,perKm,debt,recent);}}
